// Parse the JSON data from Redis queue
const webhookData = $input.first().json.propertyName;

// Return the parsed webhook data with body structure  
return [{ json: { body: webhookData } }];

// Update processing statistics
const currentStats = $input.first().json.queue_stats;
let stats = {};

if (currentStats) {
  try {
    stats = JSON.parse(currentStats);
  } catch (e) {
    stats = { processed: 0, errors: 0, lastProcessed: null };
  }
} else {
  stats = { processed: 0, errors: 0, lastProcessed: null };
}

// Check if there was an error in the API call
const hasError = $input.all().some(item => item.json.error);

if (hasError) {
  stats.errors += 1;
} else {
  stats.processed += 1;
}

stats.lastProcessed = new Date().toISOString();

return [{ json: { stats: JSON.stringify(stats) } }];

