(() => {
  // 1) Pegamos o SKU do nó "Split Out"
  const sku = $('Split Out2').item.json.produto.sku || '';

  // 2) Helper para simular indexOf(...)=0
  //    (isto é, "começa com" tal prefixo)
  function startsWith(str, prefix) {
    return str.indexOf(prefix) === 0;
  }

  // 3) Replicamos cada verificação:
  if (startsWith(sku, '19')) {
    // Se começar com '19'
    return '[{"descricao":"OC Diversos"}]';

  } else if (startsWith(sku, 'LD')) {
    return '[{"descricao":"OC LDRU"},{"descricao":"SP"}]';

  } else if (startsWith(sku, 'TH')) {
    return '[{"descricao":"OC Tiger"},{"descricao":"SP"}]';

  } else if (startsWith(sku, 'L0')) {
    return '[{"descricao":"OC LEFS"},{"descricao":"SP"}]';

  /*
   * Se você realmente precisa checar "substring(0,1) = '' + '0'",
   * adapte aqui. Exemplo, se SKU começa com '0':
   *
   * } else if (startsWith(sku, '0')) {
   *   return '[{"descricao":"..."}]';
   */

  } else if (sku.length === 6) {
    return '[{"descricao":"OC ACA"},{"descricao":"CWB"}]';

  } else if (startsWith(sku, 'G')) {
    return '[{"descricao":"OC GAUSS"},{"descricao":"CWB"}]';

  } else if (startsWith(sku, 'M')) {
    return '[{"descricao":"OC MRMK"},{"descricao":"SP"}]';

  } else if (startsWith(sku, 'CAK')) {
    return '[{"descricao":"OC Delphi"},{"descricao":"SP"}]';

  } else if (startsWith(sku, 'CS')) {
    return '[{"descricao":"OC Delphi"},{"descricao":"SP"}]';

  } else {
    // Caso nenhuma condição seja atendida
    return '[{"descricao":"Verificar SKU"}]';
  }
})()
}}

